row.arkime:
ip.src == $MPNET
&& protocols == [tls && http]
&& http.user-agent == "*Mozilla*"
&& tls.ja3 != $BROWSER_JA3_RANGE
// JA3 covers most known-malicious implant fingerprints. See Suricata column for
// JA4 if your sensor supports it.

row.suricata:
alert tls $HOME_NET any
  -> $EXTERNAL_NET 443
  (msg:"TA0011 T1573 JA4 / UA
    mismatch claimed browser TLS
    fingerprint inconsistent";
  flow:established,to_server;
  ja3.hash;
  classtype:trojan-activity;
  sid:9157303; rev:1;)

alert tcp $HOME_NET any
  -> $FILE_SERVERS 445
  (msg:"TA0009 T1039 SMB access
    high-sensitivity filename
    collection target";
  flow:established,to_server;
  pcre:"/(password|passwd|secret|
    credential|confidential|
    payroll|salary|ssn|tax|
    merger|acquisition)/i";
  classtype:trojan-activity;
  sid:9103903; rev:1;)

alert tcp $HOME_NET any
  -> $HOME_NET any
  (msg:"TA0007 T1046 Likely nmap
    top ports scan many ports
    single host";
  flow:to_server;
  flags:S;
  threshold:type both,
    track by_src,
    count 100, seconds 120;
  classtype:attempted-recon;
  sid:9104603; rev:1;)

alert tcp $MGMT_VLAN any
  -> $EXTERNAL_NET
  [80,443,8443,4444,6666]
  (msg:"TA0001 T1195.003 Hardware
    mgmt interface outbound to
    non-vendor infrastructure";
  flow:established,to_server;
  threshold:type both,
    track by_src,
    count 1, seconds 60;
  classtype:trojan-activity;
  sid:9119507; rev:1;)

alert tcp $EXTERNAL_NET any
  -> $HOME_NET 3389
  (msg:"TA0008 T1021.001 External
    RDP connection internet-exposed
    RDP abuse";
  flow:established,to_server;
  classtype:trojan-activity;
  sid:9100103; rev:1;)

alert pkthdr any any -> any any
  (msg:"RECON T1590.003 CDP/LLDP
    topology leakage";
  content:"|AA AA 03 00 00 0C|";
  offset:0; depth:6;
  classtype:policy-violation;
  sid:9159008; rev:1;)

alert tcp $HOME_NET any
  -> $EXTERNAL_NET 22
  (msg:"TA0011 T1572 Non-standard
    SSH client banner possible
    custom tunnel tool";
  flow:established,from_client;
  content:"SSH-"; depth:4;
  pcre:!"/^SSH-2\.0-(OpenSSH|
    PuTTY|libssh|Cisco|dropbear)/";
  classtype:trojan-activity;
  sid:9157203; rev:1;)

alert tcp $HOME_NET any
  -> $CONFLUENCE_HOSTS [80,443,8090]
  (msg:"TA0009 T1213.001 Confluence
    REST API search burst single
    user many queries collection";
  flow:established,to_server;
  content:"/rest/api/content/search";
  http_uri;
  threshold:type both,
    track by_src,
    count 20, seconds 600;
  classtype:trojan-activity;
  sid:9121301; rev:1;)

alert tcp $HOME_NET any
  -> $HOME_NET 445
  (msg:"TA0007 T1135 SMB tree
    connect burst many shares
    enumeration attempt";
  flow:established,to_server;
  content:"|ff 53 4d 42 75|";
  threshold:type both,
    track by_src,
    count 5, seconds 60;
  classtype:attempted-recon;
  sid:9113502; rev:1;)
